// ============================================
// Timezone Conversion Function for UTC+6
// ============================================
function convertToUTC(timeStr) {
    // Parse hours and minutes from time string (format: "HH:MM")
    const [hours, minutes] = timeStr.split(':').map(Number);

    // UTC+6 means local time is 6 hours ahead of UTC
    // To get UTC time, subtract 6 hours from local time
    let utcHours = hours - 6;
    let utcMinutes = minutes;

    // Handle day boundary crossing
    if (utcHours < 0) {
        utcHours += 24; // Previous day
    }

    // Return as a sortable string
    return `${utcHours.toString().padStart(2, '0')}:${utcMinutes.toString().padStart(2, '0')}`;
}

// ============================================
// Helper Functions
// ============================================
function formatPairName(pair) {
    return pair.replace('_', '-').toUpperCase();
}

function filterSignalsByTime(signals, startTime, endTime) {
    // For full day range (00:00-23:59), return all signals without conversion
    if (startTime === '00:00' && endTime === '23:59') {
        return signals;
    }

    // Convert user's UTC+6 times to UTC for comparison only when filtering
    const startTimeUTC = convertToUTC(startTime);
    const endTimeUTC = convertToUTC(endTime);

    return signals.filter(s => {
        const signalTimeUTC = convertToUTC(s.time);
        return signalTimeUTC >= startTimeUTC && signalTimeUTC <= endTimeUTC;
    });
}

function getSignalStats(pair) {
    const signals = SIGNAL_DATABASE[pair] || [];
    const calls = signals.filter(s => s.direction === 'CALL').length;
    const puts = signals.length - calls;

    if (signals.length > 0) {
        return {
            total: signals.length,
            calls: calls,
            puts: puts,
            callPercentage: ((calls / signals.length) * 100).toFixed(1) + '%',
            putPercentage: ((puts / signals.length) * 100).toFixed(1) + '%'
        };
    }
    return { total: 0, calls: 0, puts: 0, callPercentage: '0%', putPercentage: '0%' };
}

// ============================================
// Main Worker Handler
// ============================================
export default {
    async fetch(request) {
        // CORS headers
        const headers = {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': 'GET, OPTIONS',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Content-Type': 'application/json'
        };

        // Handle preflight OPTIONS request
        if (request.method === 'OPTIONS') {
            return new Response(null, { status: 204, headers });
        }

        // Only allow GET requests
        if (request.method !== 'GET') {
            return new Response(JSON.stringify({ error: 'Method not allowed. Use GET request.' }), {
                status: 405,
                headers
            });
        }

        try {
            const url = new URL(request.url);

            // Get parameters
            let pair = url.searchParams.get('pairs') || url.searchParams.get('pair') || 'USDBDT_otc';
            const startTime = url.searchParams.get('start_time') || '00:00';
            const endTime = url.searchParams.get('end_time') || '23:59';

            // Format pair name
            const formattedPair = formatPairName(pair);

            // Get signals
            const signals = SIGNAL_DATABASE[formattedPair] || [];

            if (!signals || signals.length === 0) {
                return new Response(JSON.stringify({
                    status: 'error',
                    message: `Pair ${formattedPair} not found`,
                    availablePairs: Object.keys(SIGNAL_DATABASE)
                }), { status: 404, headers });
            }

            // Filter by time (using UTC+6 conversion)
            const filteredSignals = filterSignalsByTime(signals, startTime, endTime);

            // Get signal stats
            const stats = getSignalStats(formattedPair);

            // Prepare response with UTC+6 timezone info
            const responseData = {
                status: 'success',
                info: {
                    provider: 'JUMMUU BOT',
                    contact: '@jummuubot',
                    system: 'Operational',
                    pair: formattedPair,
                    timezone: 'UTC+6 (Bangladesh Time)',
                    totalSignals: filteredSignals.length,
                    timeRange: `${startTime} - ${endTime}`,
                    statistics: {
                        totalInDatabase: stats.total,
                        calls: stats.calls,
                        puts: stats.puts,
                        callRatio: stats.callPercentage,
                        putRatio: stats.putPercentage
                    }
                },
                signals: filteredSignals
            };

            return new Response(JSON.stringify(responseData, null, 2), {
                status: 200,
                headers: {
                    ...headers,
                    'Cache-Control': 'public, max-age=300'
                }
            });

        } catch (error) {
            return new Response(JSON.stringify({
                status: 'error',
                error: error.message,
                stack: error.stack
            }), { status: 500, headers });
        }
    }
};